import React, { useState } from "react";

export default function WithdrawScreen({ balance, onWithdraw, goBack }) {
  const [amount, setAmount] = useState("");

  const handleWithdraw = () => {
    if (!amount || isNaN(amount) || amount <= 0) return;
    if (Number(amount) > balance) return;
    onWithdraw(Number(amount));
    setAmount("");
  };

  return (
    <div className="px-6 pb-24 bg-gray-50 min-h-screen">
      <div className="flex items-center mb-6">
        <button onClick={goBack} className="text-teal-600 font-medium mr-4">
          ← Back
        </button>
        <h1 className="text-2xl font-bold">Withdraw Funds</h1>
      </div>

      <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100 space-y-4">
        <p className="text-gray-500">Available balance: ${balance}</p>
        <input
          type="number"
          placeholder="Enter amount"
          className="w-full border border-gray-200 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-red-500"
          value={amount}
          onChange={(e) => setAmount(e.target.value)}
        />
        <button
          onClick={handleWithdraw}
          className="w-full py-3 bg-red-600 text-white rounded-xl hover:bg-red-700 transition-colors"
        >
          Withdraw
        </button>
      </div>
    </div>
  );
}
